"use client";

import { memo, useCallback, useId, useMemo, type MouseEvent } from "react";
import {
  DEFAULT_PROJECT_CARD_LABELS,
  type ProjectCard01Labels,
  type ProjectCard01Props,
  type ProjectCardItem,
} from "./types";
import { ProjectCardGrid } from "./parts/grid";
import { ProjectCardFeature } from "./parts/feature";

function ProjectCard01Inner({
  project,
  variant,
  href,
  getHref,
  onClick,
  linkComponent = "a",
  categoryStyles,
  labels: labelsProp,
  titleClassName,
  imageClassName,
  className,
  ariaLabel,
  actions,
  loading = "lazy",
}: ProjectCard01Props) {
  const titleId = useId();

  // The internal parts still use a positional shape for the click handler
  // they pass to <a onClick={...}>. Adapt the public object-shape callback
  // to a positional one at this boundary; parts stay untouched.
  const handlePartClick = useCallback(
    (proj: ProjectCardItem, mouseEvent: MouseEvent) => {
      onClick?.({ project: proj, mouseEvent });
    },
    [onClick],
  );

  const labels = useMemo<Required<ProjectCard01Labels>>(
    () => ({ ...DEFAULT_PROJECT_CARD_LABELS, ...labelsProp }),
    [labelsProp],
  );

  // href precedence: getHref > href > project.href > '#'
  const resolvedHref =
    (getHref ? getHref(project) : undefined) ?? href ?? project.href ?? "#";

  const categoryStyle = categoryStyles?.[project.category];
  const featured = project.featured === true;

  const sharedProps = {
    project,
    status: project.status,
    featured,
    labels,
    categoryStyle,
    href: resolvedHref,
    linkComponent,
    onClick: onClick ? handlePartClick : undefined,
    ariaLabel,
    titleId,
    titleClassName,
    imageClassName,
    className,
    actions,
    loading,
  };

  if (variant === "feature") {
    return <ProjectCardFeature {...sharedProps} />;
  }

  return <ProjectCardGrid {...sharedProps} />;
}

export const ProjectCard01 = memo(ProjectCard01Inner);
ProjectCard01.displayName = "ProjectCard01";

export default ProjectCard01;

export { ProjectCard01, default } from "./project-card-01";

export type {
  ProjectCardItem,
  ProjectCard01Labels,
  ProjectCard01Props,
  ProjectCard01Variant,
  ProjectCategoryStyle,
  ProjectStatus,
} from "./types";

export { DEFAULT_PROJECT_CARD_LABELS } from "./types";

export {
  PROJECT_STATUS_CONFIG,
  type ProjectStatusConfigEntry,
} from "./lib/project-status";

import type { ComponentType, ElementType, MouseEvent, ReactNode } from "react";
import type { ProjectStatus } from "./lib/project-status";

export type { ProjectStatus };

export type ProjectCard01Variant = "grid" | "feature";

export interface ProjectCardItem {
  /** Stable identifier. Used for React keys and the default ariaLabel. */
  id: string;
  /** Headline. Rendered as <h3>. Required. */
  title: string;
  /** Editorial category (e.g. "Urban Renewal"). Used as a key into `categoryStyles`. Required. */
  category: string;
  /** Image URL. Required (can be empty string — fallback placeholder rendered when falsy). */
  image: string;
  /** Image alt-text. Optional — falls back to `title`. */
  imageAlt?: string;
  /** Short summary. Required. Both variants line-clamp it. */
  description: string;
  /** Editorial status. Required — drives the status pill. */
  status: ProjectStatus;
  /** Free-form location string ("Istanbul, Kadıköy", "Remote", etc). Optional — meta line omitted if missing. */
  location?: string;
  /** Free-form year string ("2023", "Q4 2023", "2023–2025" ranges). Optional — meta line omitted if missing. */
  year?: string;
  /** Default href for this project. Optional — overridden by `href` / `getHref` on the card. */
  href?: string;
  /** Promotional flag. Optional — adds visual lift treatment + Star title prefix. */
  featured?: boolean;
}

export interface ProjectCard01Labels {
  // ─── Status pill ────────────────────────────────────────────────
  /** Default: 'Completed'. */
  completed?: string;
  /** Default: 'In progress'. */
  ongoing?: string;
  /** Default: 'Planned'. */
  planned?: string;
  // ─── Image-area CTA (grid only) ─────────────────────────────────
  /** Hover-reveal CTA pill text. Default: 'View details'. */
  viewDetails?: string;
  // ─── A11y ───────────────────────────────────────────────────────
  /** sr-only label appended after the title for featured projects. Default: 'Featured project'. */
  featuredAriaLabel?: string;
}

export interface ProjectCategoryStyle {
  /** Tailwind class string for the category pill. Optional. */
  className?: string;
  /** Custom icon overriding the default `Building2`. Optional. */
  icon?: ComponentType<{ className?: string; "aria-hidden"?: boolean | "true" | "false" }>;
}

export interface ProjectCard01Props {
  /** The project to render. */
  project: ProjectCardItem;

  /** Visual variant. Required — no default; explicit per render site. */
  variant: ProjectCard01Variant;

  // ─── Navigation ──────────────────────────────────────────────────
  /** URL the card links to. Mutually exclusive with `getHref`. */
  href?: string;
  /** Alternative href derivation. Receives the project, returns a URL. Wins over `href` and `project.href`. */
  getHref?: (project: ProjectCardItem) => string;
  /**
   * Click handler — object-shape, fired before navigation if `href` is also
   * set. v0.2 cutover from positional `(project, mouseEvent)`.
   */
  onClick?: (args: { project: ProjectCardItem; mouseEvent: MouseEvent }) => void;
  /** Element used for the link. Default: 'a'. Pass NextLink / RemixLink / etc. */
  linkComponent?: ElementType;

  // ─── Theming ─────────────────────────────────────────────────────
  /** Map of category → className + icon override. Default: empty (universal Building2 + neutral chip). */
  categoryStyles?: Record<string, ProjectCategoryStyle>;
  /** Localized labels. Defaults are English. */
  labels?: ProjectCard01Labels;
  /** Override classes for the title. */
  titleClassName?: string;
  /** Override classes for the image. */
  imageClassName?: string;
  /** Override classes for the root <article>. */
  className?: string;

  // ─── Accessibility ───────────────────────────────────────────────
  /** Override the link's accessible name. Default: title (via aria-labelledby). */
  ariaLabel?: string;

  // ─── Nested interactives (overlay-link pattern) ──────────────────
  /** Optional cluster of buttons/links that sit ABOVE the link overlay (z-10). */
  actions?: ReactNode;

  // ─── Performance ─────────────────────────────────────────────────
  /** Image loading strategy. Default: 'lazy'. */
  loading?: "lazy" | "eager";
}

/** Default English labels — exported for consumer composition. */
export const DEFAULT_PROJECT_CARD_LABELS: Required<ProjectCard01Labels> = {
  completed: "Completed",
  ongoing: "In progress",
  planned: "Planned",
  viewDetails: "View details",
  featuredAriaLabel: "Featured project",
};

"use client";

import type { ElementType, MouseEvent, ReactNode } from "react";
import { ArrowRight, Building2, Calendar, MapPin, Star } from "lucide-react";
import { cn } from "@/lib/utils";
import type {
  ProjectCard01Labels,
  ProjectCardItem,
  ProjectCategoryStyle,
} from "../types";
import {
  PROJECT_STATUS_CONFIG,
  type ProjectStatus,
} from "../lib/project-status";
import { ImageFallback } from "../lib/image-fallback";

interface GridPartProps {
  project: ProjectCardItem;
  status: ProjectStatus;
  featured: boolean;
  labels: Required<ProjectCard01Labels>;
  categoryStyle?: ProjectCategoryStyle;
  href: string;
  linkComponent: ElementType;
  onClick?: (project: ProjectCardItem, mouseEvent: MouseEvent) => void;
  ariaLabel?: string;
  titleId: string;
  titleClassName?: string;
  imageClassName?: string;
  className?: string;
  actions?: ReactNode;
  loading: "lazy" | "eager";
}

export function ProjectCardGrid({
  project,
  status,
  featured,
  labels,
  categoryStyle,
  href,
  linkComponent: LinkComponent,
  onClick,
  ariaLabel,
  titleId,
  titleClassName,
  imageClassName,
  className,
  actions,
  loading,
}: GridPartProps) {
  const statusEntry = PROJECT_STATUS_CONFIG[status];
  const CategoryIcon = categoryStyle?.icon ?? Building2;
  const hasActions = actions != null;
  const hasMeta = project.location != null || project.year != null;

  const handleClick = onClick
    ? (e: MouseEvent<HTMLAnchorElement>) => onClick(project, e)
    : undefined;

  return (
    <article
      className={cn(
        "relative group bg-card rounded-2xl overflow-hidden shadow-sm motion-safe:hover:shadow-xl motion-safe:hover:-translate-y-2 transition-all duration-500 border border-border h-full flex flex-col",
        featured && "border-t-4 border-t-primary",
        className,
      )}
    >
      {/* Image area */}
      <div className="relative aspect-16/10 overflow-hidden">
        {project.image ? (
          <img
            src={project.image}
            alt={project.imageAlt ?? project.title}
            loading={loading}
            className={cn(
              "w-full h-full object-cover motion-safe:group-hover:scale-110 transition-transform duration-700",
              imageClassName,
            )}
          />
        ) : (
          <ImageFallback className={imageClassName} />
        )}

        {/* Subtle dark gradient overlay for badge legibility (replaces source's aggressive lime tint that competed with image content) */}
        <div
          aria-hidden="true"
          className="absolute inset-0 bg-linear-to-t from-black/60 via-black/15 to-transparent motion-safe:group-hover:from-black/70 transition-all duration-300"
        />

        {/* Status pill — top-left (always) */}
        <span
          className={cn(
            "absolute top-4 left-4 inline-flex items-center px-3 py-1.5 rounded-full text-xs font-medium",
            statusEntry.className,
          )}
        >
          {labels[status]}
        </span>

        {/* Category pill — top-right OR bottom-right when actions yields top */}
        <span
          className={cn(
            "absolute inline-flex items-center px-3 py-1.5 rounded-full text-xs font-medium backdrop-blur-sm",
            hasActions ? "bottom-4 right-4" : "top-4 right-4",
            categoryStyle?.className ?? "bg-white/20 text-white",
          )}
        >
          <CategoryIcon aria-hidden="true" className="w-3 h-3 mr-1.5" />
          {project.category}
        </span>

        {/* Actions slot — top-right, above link overlay */}
        {hasActions && (
          <div className="absolute top-4 right-4 z-10 flex gap-1.5">
            {actions}
          </div>
        )}

        {/* Hover-reveal "View details" CTA — center, decorative (clicks pass through to link) */}
        <div
          aria-hidden="true"
          className="pointer-events-none absolute inset-0 flex items-center justify-center opacity-0 motion-safe:group-hover:opacity-100 transition-opacity duration-300"
        >
          <span className="inline-flex items-center gap-2 px-6 py-3 bg-primary text-primary-foreground rounded-full font-medium shadow-md">
            {labels.viewDetails}
            <ArrowRight className="w-4 h-4 motion-safe:group-hover:translate-x-1 transition-transform rtl:rotate-180" />
          </span>
        </div>
      </div>

      {/* Link overlay — covers whole article, transparent, on top of content */}
      <LinkComponent
        href={href}
        aria-labelledby={ariaLabel ? undefined : titleId}
        aria-label={ariaLabel}
        onClick={handleClick}
        className="absolute inset-0 z-0 rounded-2xl focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 outline-none"
      />

      {/* Content */}
      <div className="p-6 flex-1 flex flex-col">
        <h3
          id={titleId}
          className={cn(
            "text-xl font-semibold text-foreground mb-3 motion-safe:group-hover:text-primary transition-colors line-clamp-2",
            titleClassName,
          )}
        >
          {featured && (
            <Star
              aria-hidden="true"
              className="inline w-4 h-4 fill-primary text-primary mr-1.5 align-baseline"
            />
          )}
          {project.title}
          {featured && (
            <span className="sr-only"> ({labels.featuredAriaLabel})</span>
          )}
        </h3>

        <p className="text-muted-foreground text-sm mb-4 line-clamp-2">
          {project.description}
        </p>

        {hasMeta && (
          <ul
            role="list"
            className="flex flex-wrap items-center gap-x-4 gap-y-2 text-sm text-muted-foreground mt-auto"
          >
            {project.location != null && (
              <li className="inline-flex items-center gap-1.5">
                <MapPin aria-hidden="true" className="w-4 h-4 text-muted-foreground/70" />
                <span>{project.location}</span>
              </li>
            )}
            {project.year != null && (
              <li className="inline-flex items-center gap-1.5">
                <Calendar aria-hidden="true" className="w-4 h-4 text-muted-foreground/70" />
                <span>{project.year}</span>
              </li>
            )}
          </ul>
        )}
      </div>
    </article>
  );
}

"use client";

import type { ElementType, MouseEvent, ReactNode } from "react";
import { Building2, Star } from "lucide-react";
import { cn } from "@/lib/utils";
import type {
  ProjectCard01Labels,
  ProjectCardItem,
  ProjectCategoryStyle,
} from "../types";
import {
  PROJECT_STATUS_CONFIG,
  type ProjectStatus,
} from "../lib/project-status";
import { ImageFallback } from "../lib/image-fallback";

interface FeaturePartProps {
  project: ProjectCardItem;
  status: ProjectStatus;
  featured: boolean;
  labels: Required<ProjectCard01Labels>;
  categoryStyle?: ProjectCategoryStyle;
  href: string;
  linkComponent: ElementType;
  onClick?: (project: ProjectCardItem, mouseEvent: MouseEvent) => void;
  ariaLabel?: string;
  titleId: string;
  titleClassName?: string;
  imageClassName?: string;
  className?: string;
  actions?: ReactNode;
  loading: "lazy" | "eager";
}

export function ProjectCardFeature({
  project,
  status,
  featured,
  labels,
  categoryStyle,
  href,
  linkComponent: LinkComponent,
  onClick,
  ariaLabel,
  titleId,
  titleClassName,
  imageClassName,
  className,
  actions,
  loading,
}: FeaturePartProps) {
  const statusEntry = PROJECT_STATUS_CONFIG[status];
  const CategoryIcon = categoryStyle?.icon ?? Building2;
  const hasActions = actions != null;

  const handleClick = onClick
    ? (e: MouseEvent<HTMLAnchorElement>) => onClick(project, e)
    : undefined;

  return (
    <article
      className={cn(
        "relative group rounded-xl overflow-hidden cursor-pointer h-full",
        featured && "ring-2 ring-primary ring-inset",
        className,
      )}
    >
      {/* Background image (uses <img> for alt + lazy + error semantics) */}
      {project.image ? (
        <img
          src={project.image}
          alt={project.imageAlt ?? project.title}
          loading={loading}
          className={cn(
            "absolute inset-0 w-full h-full object-cover motion-safe:group-hover:scale-110 transition-transform duration-500",
            imageClassName,
          )}
        />
      ) : (
        <ImageFallback className={cn("absolute inset-0", imageClassName)} />
      )}

      {/* Neutral-darken gradient overlay (NOT primary-tinted; differs from grid deliberately) */}
      <div
        aria-hidden="true"
        className="absolute inset-0 bg-linear-to-t from-black/90 via-black/40 to-transparent opacity-80 motion-safe:group-hover:opacity-90 transition-opacity duration-300"
      />

      {/* Top-left cluster: category (always) + status (only when actions yielded top-right) */}
      <div className="absolute top-3 left-3 flex flex-col items-start gap-1.5">
        <span
          className={cn(
            "inline-flex items-center text-xs px-2 py-1 rounded-full backdrop-blur-sm",
            categoryStyle?.className ?? "bg-white/20 text-white",
          )}
        >
          <CategoryIcon aria-hidden="true" className="w-3 h-3 mr-1" />
          {project.category}
        </span>
        {hasActions && (
          <span
            className={cn(
              "inline-flex items-center text-xs px-2.5 py-1 rounded-full backdrop-blur-sm",
              statusEntry.className,
            )}
          >
            {labels[status]}
          </span>
        )}
      </div>

      {/* Top-right: actions (when supplied) OR status pill */}
      {hasActions ? (
        <div className="absolute top-3 right-3 z-10 flex gap-1.5">
          {actions}
        </div>
      ) : (
        <span
          className={cn(
            "absolute top-3 right-3 inline-flex items-center text-xs px-2.5 py-1 rounded-full backdrop-blur-sm",
            statusEntry.className,
          )}
        >
          {labels[status]}
        </span>
      )}

      {/* Link overlay — covers whole article */}
      <LinkComponent
        href={href}
        aria-labelledby={ariaLabel ? undefined : titleId}
        aria-label={ariaLabel}
        onClick={handleClick}
        className="absolute inset-0 z-0 rounded-xl focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 outline-none"
      />

      {/* Bottom content block (white-on-dark, no meta row by design) */}
      <div className="absolute bottom-0 left-0 right-0 p-4 text-white">
        <h3
          id={titleId}
          className={cn(
            "font-bold text-base mb-1 text-white motion-safe:group-hover:text-primary transition-colors duration-300 line-clamp-2",
            titleClassName,
          )}
        >
          {featured && (
            <Star
              aria-hidden="true"
              className="inline w-4 h-4 fill-primary text-primary mr-1.5 align-baseline"
            />
          )}
          {project.title}
          {featured && (
            <span className="sr-only"> ({labels.featuredAriaLabel})</span>
          )}
        </h3>
        <p className="text-xs text-white/80 line-clamp-2 motion-safe:group-hover:text-white/90 transition-colors">
          {project.description}
        </p>
      </div>
    </article>
  );
}

export type ProjectStatus = "completed" | "ongoing" | "planned";

export interface ProjectStatusConfigEntry {
  /** English default label. Overridable via the `labels` prop on the card. */
  label: string;
  /** Tailwind class string for the status pill background + foreground. */
  className: string;
}

/**
 * Public status kernel. Pure data — no React imports, no DOM access.
 * Tree-shakeable + server-component-importable. Consumers can read the same
 * label / className map for status legends, filter rows, count summaries —
 * without rendering the card.
 *
 * Status is editorial — set on the data object by an editor, NOT derived from
 * a clock. There is intentionally NO `getProjectStatus(project, now)` helper.
 */
export const PROJECT_STATUS_CONFIG: Record<ProjectStatus, ProjectStatusConfigEntry> = {
  completed: {
    label: "Completed",
    className: "bg-primary text-primary-foreground",
  },
  ongoing: {
    // chart-3 (teal) instead of `bg-accent` — pro-ui's `--accent` is a near-white
    // surface token (NOT a brand color), which renders status pills invisibly.
    // Teal sits between completed (lime) and planned (grey) and reads as "active".
    label: "In progress",
    className: "bg-chart-3 text-white",
  },
  planned: {
    label: "Planned",
    className: "bg-muted text-muted-foreground border border-border",
  },
};

import { Building2 } from "lucide-react";
import { cn } from "@/lib/utils";

export function ImageFallback({ className }: { className?: string }) {
  return (
    <div
      className={cn(
        "flex h-full w-full items-center justify-center bg-muted",
        className,
      )}
    >
      <Building2
        aria-hidden="true"
        className="h-8 w-8 text-muted-foreground/40"
      />
    </div>
  );
}
